var allData = mlContext.Data.LoadFromTextFile<ChurnInput>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2, seed: 42);

// Map "Yes"/"No" string to boolean Label column
var labelKeys = new[] { "Yes", "No" };
var labelVals = new[] { true, false };

var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
        inputColumnName: nameof(ChurnInput.Churned))
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age), nameof(ChurnInput.Income), "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Log evaluation metrics
var predictions = model.Transform(split.TestSet);
try
{
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
    Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");
}
catch (ArgumentOutOfRangeException)
{
